 import { getEntries, removeById, rebalance, getDiagnostics } from './priority-queue.js';

-const _cachedEntries = getEntries();
-
 let _assignmentCount = 0;
 let _rebalanceInterval = null;

 export async function pickNextTask() {
-    if (_cachedEntries.length === 0) return null;
+    const entries = getEntries(); // Always work on the current state of the queue
+    if (entries.length === 0) return null;

         let bestIdx = 0;
-    for (let i = 1; i < _cachedEntries.length; i++) {
-        if (_cachedEntries[i].priority > _cachedEntries[bestIdx].priority) {
+    for (let i = 1; i < entries.length; i++) {
+        if (entries[i].priority > entries[bestIdx].priority) {
             bestIdx = i;
         }
     }

-    const task = _cachedEntries[bestIdx];
+    const task = entries[bestIdx];

         await verifyTaskNotCancelled(task.id);

-    removeById(task.id);
-    _assignmentCount++;
+    // Attempt to remove the task from the main queue and only proceed if successful
+    if (removeById(task.id)) {
+        _assignmentCount++;
+        return task;
+    } else {
+        // Task was already removed by another worker or a rebalance cycle, effectively a no-op
+        // This prevents duplicate assignments when another worker was faster
+        console.log(`[Scheduler] Task ${task.id} already removed from queue, skipping assignment.`);
+        return null;
+    }

-    return task;
     }
